        @Override
        public UUID deserialize(ByteBuffer bytes, ProtocolVersion protocolVersion)
        {
            return bytes == null || bytes.remaining() == 0
                   ? null
                   : new UUID(bytes.getLong(bytes.position()), bytes.getLong(bytes.position() + 8));
